SELECT extension_id, COUNT(*) AS total_reviews
FROM extension_reviews
GROUP BY extension_id;

SELECT total_downloads
FROM extensions
WHERE extension_id = 1;

SELECT name
FROM extensions
WHERE rating = (SELECT MAX(rating) FROM extensions);

SELECT name
FROM extensions
WHERE total_downloads = (SELECT MAX(total_downloads) FROM extensions);

SELECT name, rating AS average_rating
FROM extensions
WHERE total_downloads > 1000;

SELECT name, total_downloads
FROM extensions
ORDER BY total_downloads DESC;

SELECT extension_id, total_downloads
FROM extensions
ORDER BY total_downloads DESC;

SELECT name, rating
FROM extensions
ORDER BY rating DESC;

SELECT version_name 
FROM extension_versions 
WHERE release_date = (SELECT MAX(release_date) FROM extension_versions);
